using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further",
        "then", "once", "here", "there", "when", "where", "why", "how",
        "all", "both", "each", "few", "more", "most", "other", "some",
        "such", "no", "nor", "not", "only", "own", "same", "so", "than",
        "too", "very", "can", "will", "just", "do", "should", "now",
        "he", "she", "it", "they", "we", "you", "i", "me", "my", "his",
        "her", "its", "our", "your", "their", "this", "that", "these",
        "those", "am", "been", "being", "have", "has", "had", "having",
        "does", "did", "doing", "would", "could", "might", "must", "shall",
        "about", "up", "also", "if", "while", "which", "what", "who"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i); // preserve original order

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    public static List<string> SplitIntoSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                freq.TryGetValue(word, out int count);
                freq[word] = count + 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var results = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            double score = 0;
            var words = TokenizeWords(sentences[i]);

            foreach (var word in words)
            {
                if (wordFrequencies.TryGetValue(word, out int freq))
                    score += (double)freq / maxFreq;
            }

            // Normalize by word count to avoid bias toward long sentences
            if (words.Count > 0)
                score /= words.Count;

            results.Add((i, score));
        }

        return results;
    }

    private static List<string> TokenizeWords(string sentence)
    {
        return WordRegex()
            .Matches(sentence)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly DocumentSummarizer _summarizer;

    public SummaryController(DocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var sentences = DocumentSummarizer.SplitIntoSentences(request.Text);
        var summary = _summarizer.Summarize(request.Text, request.MaxSentences);
        var summarySentences = DocumentSummarizer.SplitIntoSentences(summary);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = summarySentences.Count
        });
    }
}

